import { React, useEffect } from 'react'
import useBook from '../hooks/useBook';
import { Outlet, useNavigate } from 'react-router-dom';
import { Button, TextField, Grid } from '@mui/material';
import { TuneRounded } from '@mui/icons-material';
import appTheme from '../theme';


const SearchBar = () => {

    const { loading, getBookList, clearBookList, search, setSearch } = useBook()

    const { query } = search

    const navigate = useNavigate();

    const textFieldStyles = {
        backgroundColor: 'rgba(119,154,74,0.25)',
        padding: '0',
        color: appTheme.palette.primary.dark
    }

    

    const handleSearch = (e) => {
        e.persist(); // Persistir el evento para asegurar disponibilidad asíncrona
        setSearch((prevSearch) => ({
          ...prevSearch,
          [e.target.name]: e.target.value,
        }));
      };
    
      // Utilizar useEffect para realizar la búsqueda después de la actualización del estado
      useEffect(() => {
        const delaySearch = setTimeout(() => {
          if (query.trim() === '') {
            clearBookList();
          } else {
            getBookList(query, loading);
            navigate('list', { replace: true });
          }
        }, 300); // Un retraso de 300 milisegundos antes de realizar la búsqueda
    
        return () => clearTimeout(delaySearch); // Limpiar el temporizador en cada cambio del estado de búsqueda
      }, [query, loading, navigate, getBookList, clearBookList]);

  return (
      <>
       
            <Grid container spacing={0} p={2}>
            <Grid item xs={10}>
                <TextField
                fullWidth
                label='Buscar por título, autor...'
                type="text"
                name="query"
                onChange={handleSearch}
                value={query}
                variant="filled"
                size="small"
                sx={textFieldStyles}
                InputProps={{
                    disableUnderline: true,
                    sx: {
                        borderBottom: 'none',
                        
                }
                  }}
                InputLabelProps={{
                    sx: { color: appTheme.palette.primary.dark, fontWeight: '500', fontSize: '14px' }
                }}
                />
            </Grid>
            <Grid item xs={2}>
                <Button type="button" variant="contained" color="primary" style={{borderRadius: '0', maxHeight: '100px'}}  onClick={() => {}}>
                <TuneRounded sx={{ minHeight: '35px', width: '100%' }}/>
                </Button>
            </Grid>
            
            </Grid>

        <Outlet></Outlet>
      </>
        
  )
}

export default SearchBar
